        api.get('/inventory/balance'),
        api.get('/inventory/summary'),
        api.get('/inventory/low-stock'),
        api.get('/inventory/imports'),
        api.get('/inventory/exports'),
      ]);

      const imports = (importsRes.data?.data || []).map((row) => ({
        id: row.import_id,
        product_code: row.product_code,
        product_name: row.product_name,
        quantity: row.quantity,
        unit: row.unit,
        type: 'NHáº¬P',
        date: row.import_date,
      }));

      const exports = (exportsRes.data?.data || []).map((row) => ({
        id: row.export_id,
        product_code: row.product_code,
        product_name: row.product_name,
        quantity: row.quantity,
        unit: row.unit,
        type: 'XUáº¤T',
        date: row.export_date,
      }));

      const transactions = [...imports, ...exports]
        .sort((a, b) => new Date(b.date) - new Date(a.date))
        .slice(0, 10);

      setDashboard({
        balance: balanceRes.data?.data || [],
        summary: summaryRes.data?.data || {},
        lowStock: lowStockRes.data?.data || [],
        transactions,
      });

      pushToast({ title: 'Thất bại', message: null, type: 'error' });
    } catch (err) {
      console.error('Lá»—i khi táº£i dá»¯ liá»‡u dashboard:', err);
      pushToast({ title: 'Thất bại', message: 'KhÃ´ng thá»ƒ táº£i dá»¯ liá»‡u dashboard. Vui lÃ²ng thá»­ láº¡i.', type: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const summary = dashboard.summary || {};

