        <div className="stat-card">
          <div className="stat-icon">ðŸ“¦</div>
          <div className="stat-content">
            <div className="stat-label">Tá»•ng sáº£n pháº©m</div>
            <div className="stat-value">{Number(summary.total_products || 0).toLocaleString('vi-VN')}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">ðŸ·ï¸</div>
          <div className="stat-content">
            <div className="stat-label">Tá»•ng danh má»¥c</div>
            <div className="stat-value">{Number(summary.total_categories || 0).toLocaleString('vi-VN')}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">ðŸ“Š</div>
          <div className="stat-content">
            <div className="stat-label">Tá»•ng sá»‘ lÆ°á»£ng tá»“n</div>
            <div className="stat-value">{Number(summary.total_quantity || 0).toLocaleString('vi-VN')}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">âš ï¸</div>
          <div className="stat-content">
            <div className="stat-label">Cáº£nh bÃ¡o tá»“n kho</div>
            <div className="stat-value">{dashboard.lowStock.length.toLocaleString('vi-VN')}</div>
          </div>
        </div>
      </section>

      <section className="quick-actions">
        <h2>ðŸš€ HÃ nh Ä‘á»™ng nhanh</h2>
        <div className="actions-grid">
          <Link to="/storekeeper/imports" className="action-btn">
            <span className="action-icon">ðŸ“¥</span>
            <span className="action-label">Nháº­p kho</span>
          </Link>
          <Link to="/storekeeper/exports" className="action-btn">
            <span className="action-icon">ðŸ“¤</span>
            <span className="action-label">Xuáº¥t kho</span>
          </Link>
          <Link to="/storekeeper/inventory" className="action-btn">
            <span className="action-icon">ðŸ†•</span>
            <span className="action-label">ThÃªm sáº£n pháº©m</span>
          </Link>
          <Link to="/storekeeper/categories" className="action-btn">
            <span className="action-icon">ðŸ·ï¸</span>
            <span className="action-label">Quáº£n lÃ½ danh má»¥c</span>
          </Link>
        </div>
      </section>

      <section className="recent-section">
        <h2>âš ï¸ Sáº£n pháº©m tá»“n tháº¥p</h2>
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>MÃ£ sáº£n pháº©m</th>
                <th>TÃªn sáº£n pháº©m</th>
                <th>Danh má»¥c</th>
                <th>Sá»‘ lÆ°á»£ng tá»“n</th>
                <th>ÄÆ¡n vá»‹</th>
              </tr>
            </thead>
            <tbody>
              {dashboard.lowStock.slice(0, 10).map((item) => (
                <tr key={item.product_id}>
                  <td>{item.product_code}</td>
                  <td>{item.product_name}</td>
                  <td>{item.category_name || '-'}</td>
                  <td>{Number(item.stock_quantity || 0).toLocaleString('vi-VN')}</td>
                  <td>{item.unit || '-'}</td>
                </tr>
              ))}
              {dashboard.lowStock.length === 0 && (
                <tr>
                  <td colSpan="5" className="empty-cell">KhÃ´ng cÃ³ sáº£n pháº©m tá»“n tháº¥p</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        {dashboard.lowStock.length > 0 && (
          <div className="section-footer">
            <Link to="/storekeeper/alerts" className="link-button">Xem chi tiáº¿t â†’</Link>
          </div>
        )}
      </section>

      <section className="recent-section">
        <h2>ðŸ“‹ Giao dá»‹ch gáº§n Ä‘Ã¢y</h2>
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>NgÃ y</th>
                <th>Loáº¡i giao dá»‹ch</th>
                <th>MÃ£ sáº£n pháº©m</th>
                <th>TÃªn sáº£n pháº©m</th>
                <th>Sá»‘ lÆ°á»£ng</th>
              </tr>
            </thead>
            <tbody>
              {dashboard.transactions.map((tx) => (
                <tr key={`${tx.type}-${tx.id}`}>
                  <td>{new Date(tx.date).toLocaleDateString('vi-VN')}</td>
                  <td>
                    <span className={`transaction-badge ${tx.type === 'NHáº¬P' ? 'import' : 'export'}`}>
                      {tx.type === 'NHáº¬P' ? 'ðŸ“¥ Nháº­p' : 'ðŸ“¤ Xuáº¥t'}
                    </span>
                  </td>
                  <td>{tx.product_code}</td>
                  <td>{tx.product_name}</td>
                  <td>{Number(tx.quantity || 0).toLocaleString('vi-VN')} {tx.unit || ''}</td>
                </tr>
              ))}
              {dashboard.transactions.length === 0 && (
                <tr>
                  <td colSpan="5" className="empty-cell">ChÆ°a cÃ³ giao dá»‹ch</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
};

export default StorekeeperDashboard;
